    gk.TextColor3 = Color3.fromRGB(255,140,0)
    gk.Font = Enum.Font.GothamMedium
    gk.TextSize = 14
    gk.Parent = card
    Instance.new("UICorner", gk).CornerRadius = UDim.new(0,8)
    gk.MouseButton1Click:Connect(function()
        if setclipboard then pcall(setclipboard, "${getKeyLink}") end
