    local result = nil
    input.FocusLost:Connect(function(enter) if enter then btn:Activate() end end)
    btn.MouseButton1Click:Connect(function()
        local key = input.Text:match("^%s*(.-)%s*$")
        if key == "" then err.Text = "Please enter a key" return end
