interface Script {
  id: string;
  name: string;
  description: string | null;
  version: string;
  content: string;
  visibility: "PUBLIC" | "PRIVATE" | "OBFUSCATED";
  channel: "STABLE" | "BETA";
  status: "ACTIVE" | "MAINTENANCE" | "DISABLED";
  category: string | null;
  createdAt: string;
}

export default function ScriptManager() {
  const [scripts, setScripts] = useState<Script[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [resultModalOpen, setResultModalOpen] = useState(false);
  const [resultLoadstring, setResultLoadstring] = useState("");
  const [resultScriptName, setResultScriptName] = useState("");
  const [saving, setSaving] = useState(false);
  const [editingScript, setEditingScript] = useState<Script | null>(null);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [version, setVersion] = useState("1.0.0");
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("General");
  const [obfuscate, setObfuscate] = useState(false);
  const [keyMode, setKeyMode] = useState<"key" | "keyless">("key");
  const [uiLibrary, setUiLibrary] = useState<"firelab" | "custom">("firelab");

  async function fetchScripts() {
    try {
      setLoading(true);
      const res = await fetch("/api/scripts");
      const data = await res.json();
      if (data.scripts) setScripts(data.scripts);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => { fetchScripts(); }, []);

  const resetForm = () => {
    setName(""); setDescription(""); setVersion("1.0.0"); setContent("");
    setCategory("General"); setObfuscate(false); setKeyMode("key");
    setEditingScript(null);
  };

  const buildLoadstring = (scriptId: string, keyless: boolean, useCustomUi: boolean) => {
    const origin = typeof window !== "undefined" ? window.location.origin : "";
    const loaderUrl = `${origin}/api/v1/loader/${scriptId}`;
    const params = useCustomUi ? "?ui=custom" : "";
    if (keyless) {
      return `loadstring(game:HttpGet("${loaderUrl}${params}"))()`;
    }
    return `script_key = script_key or "" -- Set your key here or leave empty for prompt
loadstring(game:HttpGet("${loaderUrl}${params}"))()`;
  };

  const handleCreateOrUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim()) return;
    setSaving(true);

    const payload = {
      name, description, version, content,
      obfuscate,
      visibility: (keyMode === "keyless" ? "PUBLIC" : obfuscate ? "OBFUSCATED" : "PRIVATE") as "PUBLIC" | "OBFUSCATED" | "PRIVATE",
      channel: "STABLE" as const,
      status: "ACTIVE" as const,
      category,
    };

    try {
      const url = editingScript ? `/api/scripts/${editingScript.id}` : "/api/scripts";
      const method = editingScript ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json();
      if (res.ok && data.script) {
        const scriptId = data.script.id;
        const ls = buildLoadstring(scriptId, keyMode === "keyless", uiLibrary === "custom");
        setResultLoadstring(ls);
        setResultScriptName(data.script.name);
        setModalOpen(false);
        setResultModalOpen(true);
        resetForm();
        fetchScripts();
      } else {
        alert(data.error || "Failed to protect script");
      }
    } catch (err) {
      alert("Failed to connect to server");
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleEditClick = (script: Script) => {
    setEditingScript(script);
    setName(script.name);
    setDescription(script.description || "");
    setVersion(script.version);
    setContent(script.content);
    setCategory(script.category || "General");
    setObfuscate(script.visibility === "OBFUSCATED");
    setModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this protected script?")) return;
    try {
      const res = await fetch(`/api/scripts/${id}`, { method: "DELETE" });
      if (res.ok) fetchScripts();
      else alert("Failed to delete script");
    } catch (err) { console.error(err); }
