                  ) : (
                    <>This script is <strong className="text-red-300">keyless</strong> — anyone can run it without a key.</>
                  )}
                </p>
              </div>

              <div className="flex justify-end gap-2 pt-2">
                <Button onClick={() => setResultModalOpen(false)} variant="glow">Done</Button>
